import React, { Component } from 'react';

class Ingredients extends Component {
  render() {
    const ingredients = this.props.ingredients;

    return (
      <div className="subcontent">
      <div className="subheading">Ingredients:</div>
        <table>
          <tbody>
            {ingredients && ingredients.map((curr_ingredient, index) => (
              <tr key={index}>
                <td>{curr_ingredient.name}</td>
                <td>{curr_ingredient.amount}  {curr_ingredient.unit.length > 0 && curr_ingredient.unit}</td>
                <td>{curr_ingredient.amount_in_grams && " (" + parseFloat(curr_ingredient.amount_in_grams).toFixed(2) + " g)"}</td>
                <td>{curr_ingredient.price ? (" $" + parseFloat(curr_ingredient.price).toFixed(2)) : ""}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }
}

export default Ingredients;
