import React, { Component } from 'react';
import Ingredients from "./recipe/Ingredients.js";
import IngredientCategories from "./recipe/IngredientCategories.js";
import Directions from "./recipe/Directions.js";
import Nutrition from "./recipe/Nutrition.js";

class Recipe extends Component {
  render() {
    let recipe = this.props.recipe;
    let ingredients = recipe.ingredients;
    let ingredient_categories = recipe.ingredient_categories;
    let directions = recipe.directions;
    let nutrition = recipe.nutrition;


    return (
      <div className="recipe content">
        <div className="heading">{recipe.name}</div>
        {ingredients && <Ingredients ingredients={ingredients}/>}
        {ingredient_categories && <IngredientCategories ingredient_categories={ingredient_categories}/>}
        {directions && <Directions directions={directions}/>}
        {nutrition && <Nutrition nutrition={nutrition}/>}
      </div>
    );
  }
}

export default Recipe;
