import React, { Component } from 'react';

class IngredientCategories extends Component {
  render() {
    const categories = this.props.ingredient_categories;
    let categoriesFlattened = []; // need to turn the nested array into a "flat" one

    categories.forEach((category) => {
      categoriesFlattened.push(category);
      category.ingredients.forEach((ingredient) => {
        categoriesFlattened.push(ingredient);
      });
    });

    return (
      <div className="subcontent">
        <div className="subheading">Ingredients:</div>
        <table>
          <tbody>
            {categoriesFlattened && categoriesFlattened.map((currItem, index) => (
              <tr key={index}>
                <td className={currItem.ingredients ? "ingredient-category" : ""}>{currItem.name}{currItem.ingredients ? ":" : ""}</td>
                <td>{currItem.amount && currItem.amount + (currItem.unit.length > 0 && " " + currItem.unit)}</td>
                <td>{currItem.amount_in_grams && " (" + parseFloat(currItem.amount_in_grams).toFixed(2) + " g)"}</td>
                <td>{currItem.price ? (" $" + parseFloat(currItem.price).toFixed(2)) : ""}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    );
  }
}

export default IngredientCategories;
